"use server";
import { revalidatePath } from "next/cache";
import { getSupabaseServerClient } from "@/lib/supabase/server";

export async function createFriendAction(formData: FormData) {
  const supabase = await getSupabaseServerClient();
  const { data: userData } = await supabase.auth.getUser();
  if (!userData.user) return { ok: false, error: "Not authenticated" } as const;
  const payload = {
    name: String(formData.get("name") || ""),
    image_url: String(formData.get("image_url") || ""),
    role: String(formData.get("role") || ""),
    description: String(formData.get("description") || ""),
  };
  const { error } = await supabase.from("friends").insert(payload);
  if (error) return { ok: false, error: error.message } as const;
  revalidatePath("/admin/friends");
  revalidatePath("/");
  return { ok: true } as const;
}

export async function updateFriendAction(formData: FormData) {
  const supabase = await getSupabaseServerClient();
  const { data: userData } = await supabase.auth.getUser();
  if (!userData.user) return { ok: false, error: "Not authenticated" } as const;
  const id = String(formData.get("id") || "");
  const updates = {
    name: String(formData.get("name") || ""),
    image_url: String(formData.get("image_url") || ""),
    role: String(formData.get("role") || ""),
    description: String(formData.get("description") || ""),
  };
  const { error } = await supabase.from("friends").update(updates).eq("id", id);
  if (error) return { ok: false, error: error.message } as const;
  revalidatePath("/admin/friends");
  revalidatePath("/");
  return { ok: true } as const;
}

